def sang_trai():
    if song:
        xe_em.setx(max(xe_em.xcor() - 100, -100))


def sang_phai():
    if song:
        xe_em.setx(min(xe_em.xcor() + 100, 100))


man_hinh.listen()
man_hinh.onkey(sang_trai, "Left")
man_hinh.onkey(sang_phai, "Right")

def lan_co_xe(x):
    for xe in xe_doi:
        if xe.xcor() == x and xe.ycor() > 180:
            return True
    return False


def tao_xe_doi():
    lan = random.choice(LAN_XE)
    if lan_co_xe(lan):
        return
    xe = turtle.Turtle()
    xe.shape("square")
    xe.color(random.choice(["red", "orange", "purple"]))
    xe.shapesize(2, 3)
    xe.penup()
    xe.goto(lan, 300)
    xe_doi.append(xe)
